        if (namespace != null) {
            el = doc.createElementNS(namespace, tagName);
        } else {
            el = doc.createElement(tagName);
        }
        copyAttributes(sourceEl, el);
        if (dest == null) { // sets up the root
            doc.appendChild(el);
        } else {
